<div class="card border-0 shadow-sm"><div class="card-header bg-white"><form class="row g-2 align-items-end"><div class="col-md-6"><label class="form-label">Search</label><input class="form-control" name="search" value="<?php echo e(request('search')); ?>" placeholder="Name, email, phone, subject, message"></div><div class="col-md-3"><label class="form-label">Status</label><select class="form-select" name="status"><option value="">All</option><option value="unread" <?php if(request('status')==='unread'): echo 'selected'; endif; ?>>Unread</option><option value="read" <?php if(request('status')==='read'): echo 'selected'; endif; ?>>Read</option></select></div><div class="col-md-3"><button class="btn btn-primary-brand">Filter</button><a class="btn btn-outline-secondary" href="<?php echo e(route('admin.contact-messages.index')); ?>">Reset</a></div></form></div><div class="card-body p-0"><div class="table-responsive"><table class="table align-middle mb-0"><thead><tr><th>Name</th><th>Email</th><th>Phone</th><th>Subject</th><th>Status</th><th>Date</th><th class="text-end">Actions</th></tr></thead><tbody><?php $__empty_1 = true; $__currentLoopData = $messages; $__env->addLoop($__currentLoopData); foreach($__currentLoopData as $message): $__env->incrementLoopIndices(); $loop = $__env->getLastLoop(); $__empty_1 = false; ?><tr><td><?php echo e($message->full_name); ?></td><td><?php echo e($message->email); ?></td><td><?php echo e($message->phone ?? '—'); ?></td><td><?php echo e($message->subject ?? '—'); ?></td><td><span class="badge <?php echo e($message->is_read ? 'text-bg-secondary' : 'text-bg-danger'); ?>"><?php echo e($message->is_read ? 'Read' : 'Unread'); ?></span></td><td><?php echo e($message->created_at?->format('M d, Y H:i')); ?></td><td class="text-end"><a class="btn btn-sm btn-outline-primary-brand" href="<?php echo e(route('admin.contact-messages.show', $message)); ?>">View</a><form class="d-inline" method="POST" action="<?php echo e($message->is_read ? route('admin.contact-messages.mark-unread',$message) : route('admin.contact-messages.mark-read',$message)); ?>"><?php echo csrf_field(); ?> <?php echo method_field('PATCH'); ?><button class="btn btn-sm btn-outline-secondary"><?php echo e($message->is_read ? 'Mark unread' : 'Mark read'); ?></button></form><form class="d-inline" method="POST" action="<?php echo e(route('admin.contact-messages.destroy', $message)); ?>" onsubmit="return confirm('Delete this message?')"><?php echo csrf_field(); ?> <?php echo method_field('DELETE'); ?><button class="btn btn-sm btn-outline-danger">Delete</button></form></td></tr><?php endforeach; $__env->popLoop(); $loop = $__env->getLastLoop(); if ($__empty_1): ?><tr><td colspan="7" class="text-center text-muted py-4">No contact messages found.</td></tr><?php endif; ?></tbody></table></div></div><div class="card-footer bg-white"><?php echo e($messages->links()); ?></div></div>
